import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
import App from './App';
import * as serviceWorker from './serviceWorker';
import { library } from '@fortawesome/fontawesome-svg-core';
import { 
    faHome, 
    faLaptopCode,
    faUser,
    faTimesCircle,
    faSuitcase } from '@fortawesome/free-solid-svg-icons';

import backImage from './images/undraw_developer_activity_bv83.svg';

library.add(faHome, faLaptopCode, faUser, faSuitcase, faTimesCircle)

ReactDOM.render(
<div className="main-new centered">
  <App /> 
  <div className="backdrop">
    <img src={backImage} alt="drop"/>
  </div>
</div> , document.getElementById('root'));

// If you want your app to work offline and load faster, you can change
// unregister() to register() below. Note this comes with some pitfalls.
// Learn more about service workers: https://bit.ly/CRA-PWA
serviceWorker.unregister();
